patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -6,7 +6,7 @@
   output [2:0] priority
 );

-  always @(input_bus) begin
+  always @(input_bus or valid_flag) begin
     if (!valid_flag) begin
       priority = 3'b0;
     end else if (input_bus[7])

before_code:
module priority_encoder (
  input [7:0] input_bus,
  input valid_flag,
  output reg [2:0] priority
);

  always @(input_bus) begin
    if (!valid_flag) begin
      priority = 3'b0;
    end else if (input_bus[7])
      priority = 3'd7;
    else if (input_bus[6])
      priority = 3'd6;
    else if (input_bus[5])
      priority = 3'd5;
    else
      priority = 3'd0;
  end
endmodule

after_code:
module priority_encoder (
  input [7:0] input_bus,
  input valid_flag,
  output reg [2:0] priority
);

  always @(input_bus or valid_flag) begin
    if (!valid_flag) begin
      priority = 3'b0;
    end else if (input_bus[7])
      priority = 3'd7;
    else if (input_bus[6])
      priority = 3'd6;
    else if (input_bus[5])
      priority = 3'd5;
    else
      priority = 3'd0;
  end
endmodule
